import React, { useContext } from 'react';
import { Container } from 'react-bootstrap'; 
// Importaciones de Contextos (Solo para que no falle la compilación)
import { SettingsContext } from '../context/SettingsContext'; 

const Header = () => {
  const { settings } = useContext(SettingsContext);

  // NOTA: Se eliminó toda la lógica de usuario, carrito, búsqueda y esqueletos.
  
  return (
    // CRÍTICO: Usamos la clase CSS 'header-rounded-b' que tiene !important 
    // en index.css para forzar el redondeo de 1.5rem.
    <header 
      className="w-full sticky top-0 z-50 transition-all duration-300 shadow-md header-rounded-b" 
      style={{ backgroundColor: 'var(--brand-dark)' }} 
    >
      <Container className="py-4 text-white text-center font-bold"> 
        {/* Este texto solo es para confirmar que el Header está cargado */}
        HEADER: Prueba de Redondeo (Usando .header-rounded-b)
      </Container>
    </header>
  );
};

export default Header;
